import React, { FC, useEffect, useState } from 'react';
import { Trans } from '../module/Translation/Trans';
import { LangContextProvider } from '../module/Translation/translations.context';
import { Languages, Namespaces } from '../module/Translation/translations.types';

export const App: FC = () => {
    const { LANG_FR, LANG_EN } = Languages;

    const queryParams = new URLSearchParams(window.location.search);

    const getInitialLang = () => {
        const paramLang = queryParams.get('lang') as Languages;
        if ([LANG_EN, LANG_FR].includes(paramLang)) {
            return paramLang;
        }
        return LANG_FR;
    };

    const [lang, setLang] = useState(getInitialLang());

    const updateLangQueryParam = (value: Languages) => {
        queryParams.set('lang', value);
        window.history.pushState(null, 'null', `?${queryParams.toString()}`);
    };

    useEffect(() => {
        updateLangQueryParam(lang);
    }, [lang]);

    return (
        <LangContextProvider value={{ lang, setLang }}>
            <button type="button" onClick={() => setLang(LANG_FR)}>
                fr
            </button>
            <button type="button" onClick={() => setLang(LANG_EN)}>
                en
            </button>
            <div>
                <Trans jsonKey="welcome" namespace={Namespaces.COMMON} />
            </div>
        </LangContextProvider>
    );
};
